### 1. 병목 식별 - 통화 매칭 도메인의 N+1 및 느린 쿼리

#### 병목 1: 대기열 조회 시 N+1 쿼리

**Before (문제 코드)**

```kotlin
// domain/src/main/kotlin/com/maum/backend/entity/call/CallMatchingEntity.kt
@Entity
@Table(catalog = "maum", name = "call_matching")
class CallMatchingEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val userId: String,
    val status: Int,  // 0: 대기, 1: 매칭됨, 2: 취소

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "user_id", referencedColumnName = "id", insertable = false, updatable = false)
    val user: UserEntity? = null,  // LAZY 로딩 - N+1 유발

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)

// repository/call/CallMatchingRepository.kt
interface CallMatchingRepository : JpaRepository<CallMatchingEntity, String> {
    fun findByStatus(status: Int): List<CallMatchingEntity>  // N+1 발생: user 접근 시 추가 쿼리
}

// service/CallMatchingService.kt
@Service
class CallMatchingService(
    private val callMatchingRepository: CallMatchingRepository
) {
    fun findCandidates(): List<MatchingCandidateDto> {
        // 문제: 대기 중인 사용자 100명 조회 → user 접근 시 100번 추가 SELECT
        val waitingList = callMatchingRepository.findByStatus(0)
        return waitingList.map { matching ->
            MatchingCandidateDto(
                matchingId = matching.id,
                userName = matching.user?.name ?: "",     // N+1: 여기서 SELECT user
                userAge = matching.user?.age ?: 0,        // 이미 로드됐으면 캐시 사용
                userGender = matching.user?.gender ?: ""  // 동일
            )
        }
    }
}
```

**쿼리 수**: 대기자 100명 기준 1(대기열) + 100(user 조회) = **101 쿼리**

---

**After (fetch join + QueryDSL Projection)**

```kotlin
// repository/call/CallMatchingRepositoryCustom.kt
interface CallMatchingRepositoryCustom {
    fun findWaitingCandidatesWithUser(): List<MatchingCandidateDto>
}

// repository/call/CallMatchingRepositoryImpl.kt
@Repository
class CallMatchingRepositoryImpl(
    private val queryFactory: JPAQueryFactory
) : CallMatchingRepositoryCustom {

    override fun findWaitingCandidatesWithUser(): List<MatchingCandidateDto> {
        val matching = QCallMatchingEntity.callMatchingEntity
        val user = QUserEntity.userEntity

        // fetch join으로 N+1 제거, Projection으로 필요한 컬럼만 조회
        return queryFactory
            .select(
                Projections.constructor(
                    MatchingCandidateDto::class.java,
                    matching.id,
                    user.name,
                    user.age,
                    user.gender
                )
            )
            .from(matching)
            .innerJoin(user).on(matching.userId.eq(user.id))
            .where(matching.status.eq(0))
            .orderBy(matching.createdAt.asc())
            .fetch()
    }
}

// repository/call/CallMatchingRepository.kt
interface CallMatchingRepository : JpaRepository<CallMatchingEntity, String>,
    CallMatchingRepositoryCustom
```

**쿼리 수**: **1 쿼리** (JOIN으로 한 번에 조회)
**예상 개선**: 응답 시간 80-90% 감소 (101쿼리 → 1쿼리)

