### 2. Redis 캐시 전략

#### 캐시 적용 지점 및 TTL 설계

**After (Redis 기반 매칭 대기열)**

```kotlin
// config/RedisConfig.kt
@Configuration
class RedisConfig {
    @Bean
    fun redisTemplate(connectionFactory: RedisConnectionFactory): RedisTemplate<String, Any> {
        return RedisTemplate<String, Any>().apply {
            this.connectionFactory = connectionFactory
            keySerializer = StringRedisSerializer()
            valueSerializer = GenericJackson2JsonRedisSerializer()
            hashKeySerializer = StringRedisSerializer()
            hashValueSerializer = GenericJackson2JsonRedisSerializer()
        }
    }
}

// service/MatchingQueueService.kt
@Service
class MatchingQueueService(
    private val redisTemplate: RedisTemplate<String, Any>
) {
    companion object {
        // 매칭 대기열 키: ZSET(Sorted Set) - score = 입장 시각 (epoch millis)
        private const val MATCHING_QUEUE_KEY = "matching:queue"
        // 사용자별 매칭 상태 키: TTL 30초
        private const val MATCHING_STATUS_PREFIX = "matching:status:"
        private val QUEUE_TTL = Duration.ofMinutes(10)
        private val STATUS_TTL = Duration.ofSeconds(30)
    }

    /**
     * 대기열 입장: O(log n) - Redis ZADD
     * DB INSERT 없이 Redis에만 저장하여 응답 시간 최소화
     */
    fun enqueue(userId: String): Boolean {
        val score = System.currentTimeMillis().toDouble()
        val added = redisTemplate.opsForZSet()
            .add(MATCHING_QUEUE_KEY, userId, score)
        redisTemplate.expire(MATCHING_QUEUE_KEY, QUEUE_TTL)
        return added == true
    }

    /**
     * 매칭 시도: O(log n) - Redis ZRANGEBYSCORE + ZREM (원자적)
     * Lua 스크립트로 원자성 보장 (race condition 방지)
     */
    fun tryMatch(userId: String): String? {
        val luaScript = """
            local queue_key = KEYS[1]
            local user_id = ARGV[1]
            local current_time = tonumber(ARGV[2])

            -- 현재 유저를 제외한 가장 오래 대기한 유저 조회
            local candidates = redis.call('ZRANGE', queue_key, 0, 9)

            for _, candidate_id in ipairs(candidates) do
                if candidate_id ~= user_id then
                    -- 원자적으로 후보자 제거
                    redis.call('ZREM', queue_key, candidate_id)
                    redis.call('ZREM', queue_key, user_id)
                    return candidate_id
                end
            end
            return nil
        """.trimIndent()

        val script = RedisScript.of(luaScript, String::class.java)
        return redisTemplate.execute(
            script,
            listOf(MATCHING_QUEUE_KEY),
            userId,
            System.currentTimeMillis().toString()
        )
    }

    /**
     * 매칭 상태 캐시: TTL 30초
     * 빈번한 상태 조회를 DB 대신 Redis로 처리
     */
    fun setMatchingStatus(userId: String, status: MatchingStatus) {
        val key = "$MATCHING_STATUS_PREFIX$userId"
        redisTemplate.opsForValue().set(key, status.name, STATUS_TTL)
    }

    fun getMatchingStatus(userId: String): MatchingStatus? {
        val key = "$MATCHING_STATUS_PREFIX$userId"
        val value = redisTemplate.opsForValue().get(key) as? String
        return value?.let { MatchingStatus.valueOf(it) }
    }

    fun dequeue(userId: String) {
        redisTemplate.opsForZSet().remove(MATCHING_QUEUE_KEY, userId)
    }
}
```

#### TTL 전략 요약

| 캐시 대상 | 키 패턴 | TTL | 무효화 전략 |
|---|---|---|---|
| 매칭 대기열 | `matching:queue` | 10분 | 매칭 성공 시 ZREM |
| 사용자 매칭 상태 | `matching:status:{userId}` | 30초 | 상태 변경 시 즉시 SET |
| 사용자 프로필(매칭용) | `user:profile:{userId}` | 5분 | 프로필 수정 시 DEL |
| 차단 목록 | `block:list:{userId}` | 1분 | 차단/해제 시 DEL |

