### 3. 쿼리 최적화 - 인덱스 및 복합 조건

**Before (인덱스 없는 상태 + 프로필 조건 조회)**

```kotlin
// 문제: status, gender, age_range 복합 조건이지만 인덱스 없음
// 실행 계획: Full Table Scan
fun findMatchingCandidates(
    gender: String,
    minAge: Int,
    maxAge: Int
): List<CallMatchingEntity> {
    return callMatchingRepository.findByStatusAndUserGenderAndUserAgeBetween(
        status = 0,
        gender = gender,
        minAge = minAge,
        maxAge = maxAge
    )
}
```

**After (복합 인덱스 + QueryDSL Projection + 페이지네이션)**

```kotlin
// entity/call/CallMatchingEntity.kt
@Entity
@Table(
    catalog = "maum",
    name = "call_matching",
    indexes = [
        // 복합 인덱스: 매칭 대기열 조회 최적화
        Index(name = "idx_call_matching_status_created", columnList = "status, created_at"),
        Index(name = "idx_call_matching_user_status", columnList = "user_id, status")
    ]
)
class CallMatchingEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val userId: String,
    var status: Int,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)

// repository/call/CallMatchingRepositoryImpl.kt
@Repository
class CallMatchingRepositoryImpl(
    private val queryFactory: JPAQueryFactory
) : CallMatchingRepositoryCustom {

    /**
     * 매칭 후보자 조회: fetch join + Projection + LIMIT
     * - N+1 제거: JOIN으로 user 정보 한 번에 조회
     * - Projection: 필요한 컬럼만 선택 (SELECT * 방지)
     * - LIMIT 10: 불필요한 대량 조회 방지
     */
    override fun findTopCandidates(
        excludeUserId: String,
        blockedUserIds: List<String>,
        limit: Int = 10
    ): List<MatchingCandidateDto> {
        val matching = QCallMatchingEntity.callMatchingEntity
        val user = QUserEntity.userEntity
        val profile = QUserProfileEntity.userProfileEntity

        return queryFactory
            .select(
                Projections.constructor(
                    MatchingCandidateDto::class.java,
                    matching.id,
                    matching.userId,
                    user.nickname,
                    profile.age,
                    profile.gender,
                    profile.thumbnailUrl
                )
            )
            .from(matching)
            .innerJoin(user).on(matching.userId.eq(user.id))
            .innerJoin(profile).on(user.id.eq(profile.userId))
            .where(
                matching.status.eq(0),                          // 인덱스 활용
                matching.userId.ne(excludeUserId),
                matching.userId.notIn(blockedUserIds),          // 차단 목록 제외
                matching.createdAt.gt(                          // 10분 이내 대기자만
                    LocalDateTime.now().minusMinutes(10)
                )
            )
            .orderBy(matching.createdAt.asc())                 // 오래 기다린 순
            .limit(limit.toLong())
            .fetch()
    }

    /**
     * 배치 상태 업데이트: 개별 save() 대신 벌크 UPDATE
     * - Before: 2번의 SELECT + 2번의 UPDATE = 4 쿼리
     * - After: 1번의 UPDATE = 1 쿼리
     */
    override fun bulkUpdateStatus(matchingIds: List<String>, status: Int): Long {
        val matching = QCallMatchingEntity.callMatchingEntity
        return queryFactory
            .update(matching)
            .set(matching.status, status)
            .set(matching.updatedAt, LocalDateTime.now())
            .where(matching.id.`in`(matchingIds))
            .execute()
    }
}
```

