@Repository
class CallMatchingRepositoryImpl(
    private val queryFactory: JPAQueryFactory
) : CallMatchingRepositoryCustom {

    /**
     * 매칭 후보자 조회: fetch join + Projection + LIMIT
     * - N+1 제거: JOIN으로 user 정보 한 번에 조회
     * - Projection: 필요한 컬럼만 선택 (SELECT * 방지)
     * - LIMIT 10: 불필요한 대량 조회 방지
     */
    override fun findTopCandidates(
        excludeUserId: String,
        blockedUserIds: List<String>,
        limit: Int = 10
    ): List<MatchingCandidateDto> {
        val matching = QCallMatchingEntity.callMatchingEntity
        val user = QUserEntity.userEntity
        val profile = QUserProfileEntity.userProfileEntity

        return queryFactory
            .select(
                Projections.constructor(
                    MatchingCandidateDto::class.java,
                    matching.id,
                    matching.userId,
                    user.nickname,
                    profile.age,
                    profile.gender,
                    profile.thumbnailUrl
                )
            )
            .from(matching)
            .innerJoin(user).on(matching.userId.eq(user.id))
            .innerJoin(profile).on(user.id.eq(profile.userId))
            .where(
                matching.status.eq(0),                          // 인덱스 활용
                matching.userId.ne(excludeUserId),
                matching.userId.notIn(blockedUserIds),          // 차단 목록 제외
                matching.createdAt.gt(                          // 10분 이내 대기자만
                    LocalDateTime.now().minusMinutes(10)
                )
            )
            .orderBy(matching.createdAt.asc())                 // 오래 기다린 순
            .limit(limit.toLong())
            .fetch()
    }

    /**
     * 배치 상태 업데이트: 개별 save() 대신 벌크 UPDATE
     * - Before: 2번의 SELECT + 2번의 UPDATE = 4 쿼리
     * - After: 1번의 UPDATE = 1 쿼리
     */
    override fun bulkUpdateStatus(matchingIds: List<String>, status: Int): Long {
        val matching = QCallMatchingEntity.callMatchingEntity
        return queryFactory
            .update(matching)
            .set(matching.status, status)
            .set(matching.updatedAt, LocalDateTime.now())
            .where(matching.id.`in`(matchingIds))
            .execute()
    }
}
